transcript.content:
[
  {
    "biasType": "Spin",
    "biasedText": "Kid Rock buried Puerto Rican rapper Bad Bunny in the gossip site TMZ's poll",
    "explanation": "The word 'buried' is a sensational, interpretive verb suggesting a dramatic defeat, rather than neutrally reporting the poll result."
  },
  {
    "biasType": "Spin",
    "biasedText": "TMZ tried its best to lead its fans to pick Bad Bunny by characterizing the rabidly anti-Trump rapper's show as taking place on 'one of the world's biggest stages,' while merely saying that Kid Rock 'tried to outshine' Bad Bunny.",
    "explanation": "Frames TMZ's actions with the interpretive claim 'tried its best to lead its fans,' implying intent and manipulation beyond a neutral description."
  },
  {
    "biasType": "Mind reading",
    "biasedText": "The poll may not have gone exactly how TMZ expected as Kid Rock soared ahead...before TMZ shut the poll down.",
    "explanation": "Asserts knowledge of TMZ's expectations and implies intentional action in closing the poll, without attribution or evidence."
  },
  {
    "biasType": "Spin",
    "biasedText": "Fans did not fall for the push…",
    "explanation": "Asserts that there was a deliberate attempt ('the push') by TMZ and that fans saw through it, an interpretation of both TMZ and the fans' motives without evidence."
  },
  {
    "biasType": "Bias by Omission",
    "biasedText": "According to some of the latest statistics, it seems that nearly half of Super Bowl viewers tuned out of the league's Bad Bunny Halftime Show.",
    "explanation": "No source or context is provided for this statistic, and no alternative interpretations or perspectives are included, presenting only evidence unfavorable to Bad Bunny without balance."
  },
  {
    "biasType": "Spin",
    "biasedText": "in a strange turn of events, rapper Bad Bunny wiped all his social media accounts immediately after his Super Bowl performance.",
    "explanation": "The phrase 'in a strange turn of events' adds unnecessary sensationalism and implies unusual or suspicious motives without evidence."
  }
]

